import { monsterData } from './monsterData'
import { actionCreator } from '../redux/actionCreator'

export const onStateChange = (store) => {
  const state = store.getState()

  // MonsterKilledEvent
  if (state.currentMonster.health <= 0) {
    console.debug('handleMonsterKilledEvent')
    store.dispatch(actionCreator.handleMonsterKilledEvent(state.player.level))
    store.dispatch(actionCreator.incrementGold(Math.round(state.player.level * 1.33)))
    store.dispatch(actionCreator.incrementKillAmount(1))
  }

  // LevelUpgradeEvent
  if (state.player.levelKillAmount >= state.player.levelKillAmountRequire) {
    console.debug('handleLevelUpgradeEvent')
    store.dispatch(actionCreator.handleLevelUpgradeEvent())
  }

  // achievement
  const notSuccessAchievementList = state.achievement.filter(achievement => achievement.successDate === null)

  notSuccessAchievementList.map(achievement => {
    const successFlagList = achievement.requireList.map(require => {
      const requireTypeCurrentValue = state[require.type]
      // console.debug('requireTypeCurrentValue', requireTypeCurrentValue)
      const requireTypeItemCurrentValue = requireTypeCurrentValue[require.itemName]
      // console.debug('requireTypeItemCurrentValue', requireTypeItemCurrentValue)

      return requireTypeItemCurrentValue >= require.amount
    })
    // console.debug('successFlagList', successFlagList)

    if (successFlagList.includes(false)) {
      return
    }
    store.dispatch(actionCreator.achievementSuccess(achievement.id))
  })
}

export const randomInt = (max) => {
  return Math.floor(Math.random() * Math.floor(max))
}

export const nextMonster = () => {
  const nextMonsterIndex = randomInt(monsterData.length)
  return { ...monsterData[nextMonsterIndex] }
}

export const setTimer = (store) => {
  const timer = setInterval(() => {
    // auto attack
    playerAttack(store)
    // update event
    store.dispatch(actionCreator.update({ store }))
  }, 1000)
  console.debug('timer', timer)
}

export const getPlayerDamage = (playerState) => {
  const isCriticalHit = randomInt(100) + 1 <= playerState.criticalHitChance
  if (isCriticalHit) {
    console.debug('isCriticalHit')
    return playerState.damage * 2
  }
  return playerState.damage
}

export const playerAttack = (store) => {
  const state = store.getState()
  const playerDamage = getPlayerDamage(state.player)
  store.dispatch(actionCreator.damageMonster(playerDamage))
}
