import React from 'react'
import { useSelector } from 'react-redux'

export const AchievementPanel = () => {
  const state = useSelector(state => state)

  return (
    <details>
      <summary>Achievement</summary>
      <table>
        <thead>
        <tr>
          <th>{`Name`}</th>
          <th>{`Success Date`}</th>
        </tr>
        </thead>
        <tbody>
        {state.achievement.map(achievement => {
          return (
            <tr key={achievement.id}>
              <td>{achievement.name}</td>
              <td>{achievement.successDate ? achievement.successDate.toString() : `Not Yet`}</td>
            </tr>
          )
        })}
        </tbody>
      </table>
    </details>
  )
}
