import { actionType } from './actionType'

export const actionCreator = {
  update: (data) => {
    return {
      type: actionType.update,
      data,
    }
  },
  damageMonster: (damage) => {
    return {
      type: actionType.damageMonster,
      data: {
        damage,
      },
    }
  },
  upgrade: () => {
    return {
      type: actionType.upgrade,
    }
  },
  incrementGold: (amount) => {
    return {
      type: actionType.incrementGold,
      data: {
        amount,
      },
    }
  },
  incrementKillAmount: (amount) => {
    return {
      type: actionType.incrementKillAmount,
      data: {
        amount,
      },
    }
  },
  handleMonsterKilledEvent: (level) => {
    return {
      type: actionType.handleMonsterKilledEvent,
      data: {
        level,
      },
    }
  },
  handleLevelUpgradeEvent: () => {
    return {
      type: actionType.handleLevelUpgradeEvent,
    }
  },
  achievementSuccess: (achievementId) => {
    return {
      type: actionType.achievementSuccess,
      data: {
        achievementId
      }
    }
  }
}
