import React from 'react'
import { useSelector } from 'react-redux'

export const GameInfoPanel = () => {
  const state = useSelector(state => state)

  return (
    <fieldset>
      <legend>Game Info</legend>
      <table>
        <thead>
        <tr>
          <th>{`Game Time`}</th>
          <th>{`Total Gold`}</th>
          <th>{`Kill Amount`}</th>
        </tr>
        </thead>
        <tbody>
        <tr>
          <td>{state.gameInfo.gameTime}</td>
          <td>{state.gameInfo.totalGold}</td>
          <td>{state.gameInfo.killAmount}</td>
        </tr>
        </tbody>
      </table>
    </fieldset>
  )
}
